-- Seed data: Khibiny mountains and routes (Кольский полуостров)
-- 47 routes across multiple peaks in the Khibiny massif

INSERT INTO mountains (id, name, country, region, height, latitude, longitude, description, difficulty)
VALUES (
  'a0000000-0000-0000-0000-000000000001',
  'Хибины',
  'Россия',
  'Кольский полуостров, Мурманская область',
  1200,
  67.75,
  33.73,
  'Крупнейший горный массив на Кольском полуострове, расположенный за Полярным кругом. Геологический возраст — около 390 млн лет. Преобладающая форма горных вершин — платообразные, с довольно крутыми контрфорсами и стенами цирков. Высшая точка — гора Юдычвумчорр (1200,6 м). Горный массив предоставляет полный набор категорий трудности, от 1Б до 5А. Хибины называют «домашними горами» — сюда приезжают альпинисты со всей европейской части России перед серьёзными восхождениями. Климат субарктический, восхождения возможны круглосуточно в полярный день. Оптимальное время: летом с конца июня по середину сентября, зимой с середины февраля по конец апреля.',
  3
);

